queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?programtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasRadio_Stations ?parent . } GROUP BY ?child }
  ?child p:programType ?programtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Radio_Stations } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?programtype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasPrograms ?child ; p:hasRadio_Stations ?parent . } GROUP BY ?child }
  ?child p:programType ?programtype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Radio_Stations } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?stationname ?programtype WHERE {
  ?radio_stations_programs a :Radio_Stations_Programs .
  ?programs a :Programs .
  ?radio_stations_programs p:hasPrograms ?programs .
  ?radio_stations a :Radio_Stations .
  ?radio_stations_programs p:hasRadio_Stations ?radio_stations .
  ?radio_stations p:stationName ?stationname .
  ?programs p:programType ?programtype .
} }
}
